import React, { useState } from "react";

function App() {
  const [songs, setSongs] = useState([]);
  const [favorites, setFavorites] = useState([]);
  const [search, setSearch] = useState("");

  const musicData = {
    Happy: ["Butta Bomma", "Samajavaragamana", "Inkem Inkem"],
    Sad: ["Oosupodu", "Yedhalo Oka Mounam", "Kanulanu Thaake"],
    Love: ["Ninnu Kori", "Vachindamma", "Priyathama Priyathama"],
    Motivation: ["Life of Ram", "Seethakaalam", "Nee Prashnalu"],
    Relax: ["Nee Kallalona", "Oka Manasu", "Hrudhayam Jaripe"],
    Party: ["Ramuloo Ramulaa", "Daang Daang", "Pakka Local"],
    Devotional: ["Hanuman Chalisa", "Om Namah Shivaya", "Bhaja Govindam"]
  };

  const showSongs = (mood) => {
    setSongs(musicData[mood]);
  };

  const toggleFavorite = (song) => {
    if (favorites.includes(song)) {
      setFavorites(favorites.filter((s) => s !== song));
    } else {
      setFavorites([...favorites, song]);
    }
  };

  const filteredSongs = songs.filter((song) =>
    song.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div
      style={{
        textAlign: "center",
        minHeight: "100vh",
        padding: "20px",
        background: "linear-gradient(to right, #0f2027, #203a43, #2c5364)",
        color: "white"
      }}
    >
      <h1>🎧 Telugu Music App Pro</h1>

      {/* SEARCH BAR */}
      <input
        type="text"
        placeholder="🔍 Search songs..."
        value={search}
        onChange={(e) => setSearch(e.target.value)}
        style={{
          padding: "10px",
          width: "250px",
          borderRadius: "10px",
          border: "none",
          marginBottom: "20px"
        }}
      />

      {/* MOOD BUTTONS */}
      <div>
        {Object.keys(musicData).map((mood, index) => (
          <button
            key={index}
            onClick={() => showSongs(mood)}
            style={{
              margin: "6px",
              padding: "10px 15px",
              borderRadius: "10px",
              border: "none",
              cursor: "pointer",
              backgroundColor: "#ffcc00",
              fontWeight: "bold"
            }}
          >
            {mood}
          </button>
        ))}
      </div>

      {/* SONG DISPLAY */}
      <h2 style={{ marginTop: "20px" }}>🎶 Songs</h2>

      {filteredSongs.length === 0 ? (
        <p>Select mood or search songs</p>
      ) : (
        filteredSongs.map((song, index) => (
          <div
            key={index}
            style={{
              background: "rgba(255,255,255,0.1)",
              margin: "10px auto",
              padding: "15px",
              width: "300px",
              borderRadius: "12px",
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center"
            }}
          >
            <span>🎵 {song}</span>

            <button
              onClick={() => toggleFavorite(song)}
              style={{
                background: "transparent",
                border: "none",
                fontSize: "18px",
                cursor: "pointer",
                color: favorites.includes(song) ? "red" : "white"
              }}
            >
              ❤️
            </button>
          </div>
        ))
      )}

      {/* FAVORITES SECTION */}
      <h2>❤️ Favorites</h2>

      {favorites.length === 0 ? (
        <p>No favorites yet</p>
      ) : (
        favorites.map((song, index) => (
          <p key={index}>⭐ {song}</p>
        ))
      )}
    </div>
  );
}

export default App;
